import React, { useEffect, useState } from "react";
import { getDesigners, createDesigner, updateDesigner, deleteDesigner } from "../api";
import DesignerForm from "./DesignerForm";
import "../style.css";

const DesignerList = () => {
  const [designers, setDesigners] = useState([]);
  const [editing, setEditing] = useState(null);
  const [showForm, setShowForm] = useState(false); // <-- form hidden initially

  const fetchData = async () => {
    const { data } = await getDesigners();
    setDesigners(data);
  };

  useEffect(() => {
    fetchData();
  }, []);

  const handleAdd = async (designer) => {
    if (editing) {
      await updateDesigner(editing._id, designer);
      setEditing(null);
    } else {
      await createDesigner(designer);
    }
    fetchData();
    setShowForm(false); // hide form after submit
  };

  const handleDelete = async (id) => {
    await deleteDesigner(id);
    fetchData();
  };

  const handleEdit = (designer) => {
    setEditing(designer);
    setShowForm(true); // show form when editing
  };

  return (
    <div className="page">
      <div style={{ marginBottom: "20px" }}>
        <button className="floating-btn" onClick={() => { setShowForm(true); setEditing(null); }}>
          ➕ Add Designer
        </button>
      </div>

      {showForm && (
        <DesignerForm
          onSubmit={handleAdd}
          existingData={editing}
          onCancel={() => { setShowForm(false); setEditing(null); }}
        />
      )}

      <h3>Designers List</h3>
      <table>
        <thead>
          <tr>
            <th>Name</th><th>Email</th><th>Type</th><th>Actions</th>
          </tr>
        </thead>
        <tbody>
          {designers.map((d) => (
            <tr key={d._id}>
              <td
                className="designer-name"
                onClick={() =>
                  alert(
                    `Name: ${d.name}\nEmail: ${d.email}\nType: ${d.type}\nPrevious: ${d.previousDesigns.join(", ")}`
                  )
                }
              >
                {d.name}
              </td>
              <td>{d.email}</td>
              <td>{d.type}</td>
              <td>
                <button onClick={() => handleEdit(d)}>✏️</button>
                <button onClick={() => handleDelete(d._id)}>🗑️</button>
              </td>
            </tr>
          ))}
        </tbody>
      </table>
    </div>
  );
};

export default DesignerList;
